std::span<const Gfx1201DecoderSeedEncoding>
GetGfx1201Phase0ComputeDecoderSeeds() {
  return kSeedEncodings;
}

const Gfx1201DecoderSeedEncoding* FindGfx1201Phase0ComputeDecoderSeed(
    std::string_view encoding_name) {
  for (const Gfx1201DecoderSeedEncoding& encoding : kSeedEncodings) {
    if (encoding.encoding_name == encoding_name) {
      return &encoding;
    }
  }
  return nullptr;
}

std::span<const Gfx1201DecoderSeedEntry> GetGfx1201Phase0ComputeDecoderSeedEntries() {
  return kSeedEntries;
}

std::span<const Gfx1201DecoderSeedEntry> GetGfx1201Phase0ComputeDecoderSeedEntries(
    const Gfx1201DecoderSeedEncoding& encoding) {
  return std::span<const Gfx1201DecoderSeedEntry>(
      kSeedEntries.data() + encoding.entry_begin, encoding.entry_count);
}

bool IsGfx1201Phase0ComputeEncoding(std::string_view encoding_name) {
  return FindGfx1201Phase0ComputeDecoderSeed(encoding_name) != nullptr;
}

